function [steady_state_value, steady_state_time, settling_time] = analyzeStepResponse(sys)
    % Plot step response
    figure;
    [y, t] = step(sys);
    plot(t, y);
    title('系统的单位阶跃响应');
    xlabel('时间 (秒)');
    ylabel('输出');

