slerp_interpolation<pre><code>def slerp(q1, q2, t):
    """
    球面线性插值（Slerp）
    :param q1: 起始四元数
    :param q2: 终止四元数
    :param t: 插值因子，范围 [0, 1]
    :return: 插值后的四元数
    """
    dot_product = np.dot(q1, q2)
    dot_product = np.clip(dot_product, -1.0, 1.0)
    theta_0 = np.arccos(dot_product)
    sin_theta_0 = np.sin(theta_0)

    if sin_theta_0 &lt; 1e-6:
        return q1

    theta = theta_0 * t
    s1 = np.sin(theta) / sin_theta_0
    s0 = np.cos(theta) - dot_product * s1
    return s0 * q1 + s1 * q2
