    %处理θ为0的情况
    if theta&lt;eps
        q_interp=q0;
        return;
    end
    %计算插值系数
    k0=sin((1-t)*theta)/sin(theta);
    k1=sin(t*theta)/sin(theta);
    %线性组合并重新构造四元数
    q_interp_compact=k0*q0_compact+k1*q1_compact;
    q_interp=quaternion(q_interp_compact);
    q_interp=normalize(q_interp);
end
